var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"신호패턴 분석 중......","JPN":"シグナルパターン分析中……","ENG":"Analyzing the signal pattern...","TWN":"正在分析信號模式……"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"좌표 확인 완료.","JPN":"座標確認完了。","ENG":"Coordinates confirmed.","TWN":"完成座標確認。"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"정보가 파악되지 않은 초고심도 포인트로 차원항로를 설정합니다.","JPN":"情報把握がされていない超高深度ポイントに次元航路を設定します。","ENG":"Setting interdimensional course to the unknown hyperdepths.","TWN":"將次元航路設置為無任何情報的超深度地點。"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이터니움 드라이브 온라인.","JPN":"エタニウムドライブ、オンライン。","ENG":"Eternium Drive online.","TWN":"永恆之金引擎連線。"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"강하.","JPN":"降下。","ENG":"Descending.","TWN":"降落。"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"곧 목적지에 도착할 겁니다.","JPN":"間もなく目的地に到着します。","ENG":"We'll arrive at the destination soon.","TWN":"即將到達目的地。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"항해하는 동안 좌석은 편안하셨는지 궁금하네요.","JPN":"今回の航海はお気に召しましたか。","ENG":"Was your Dive comfortable?","TWN":"不知道航行期間座位是否舒適呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런 쓸데없는 질문은 할 필요 없다.","JPN":"そんなくだらない質問は必要ない。","ENG":"No need to ask such a silly question.","TWN":"不要問那種無聊的問題。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 확실히 놀랍군.","JPN":"だが確かに驚きではあるな。","ENG":"But this ship is certainly astounding.","TWN":"但確實令人吃驚。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 정도의 차원 압력을 뚫고 단숨에 초고심도로 진입하는 함선이라니......","JPN":"このレベルの次元圧力を突破して一気に超高深度に進入する艦船なんて……","ENG":"A ship that can withstand this level of dimensional pressure and reach the hyperdepths immediately...","TWN":"這艦船竟然能一口氣突破這種程度的次元壓力，進入超深度……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"합중국의 어떤 차원함선도 이런 성능을 가진 것은 없어.","JPN":"合衆国のどの次元艦船にも、このような性能はない。","ENG":"No one else in the States has a dimensional ship with such impressive performance.","TWN":"聯邦的任何次元戰艦都不具備這樣的性能。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"강습함 글레입니르는 구 관리국에서도 최강의 전대가 사용하던 전용함이니까요.","JPN":"強襲艦グレイプニルは、旧管理局でも最強の戦隊が使用していた専用艦です。","ENG":"This Assault Ship, Gleipnir, was once used by the Old Administration's strongest division.","TWN":"因為強襲戰艦格萊伊尼勒在舊管理局也是最強戰隊使用的專用艦。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신들이 만든 그 모조품들과 비교할 수는 없는 법이죠.","JPN":"あなた方が作った模造品とは比べ物にならないでしょう。","ENG":"It can't be compared to the imitations that you've made.","TWN":"你們製造的那些仿造品完全無法與之相比。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 좋은 배가 있다고 해서 반드시 항해가 성공하는 건 아니에요.","JPN":"しかし良い船があるからといって、必ず航海が成功するわけではありません。","ENG":"But a good ship alone doesn't guarantee a successful voyage.","TWN":"但就算有好艦船，也不能保證航行一定能成功。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"원하는 항구로 가려면 제대로 된 나침반과 지도가 필요합니다.","JPN":"目的の港に向うためには、正確なコンパスと地図が必要です。","ENG":"You need a proper compass and map to arrive at the destination safely.","TWN":"想到達要去的港口，還需要有好的羅盤和地圖。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 제공해 준 네임리스 원의 침식파 시그니처가 정확하다면 좋겠군요.","JPN":"あなたが提供してくれたネームレスワンの侵食波シグネチャーが正確であることを祈ります。","ENG":"I hope the Nameless One's Corruption ray signature you gave us is accurate.","TWN":"希望你提供的無名1侵蝕波信號是正確的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"엉뚱한 좌표에서 시간낭비를 하는 건 피차 원하는 바가 아니니까요.","JPN":"誤った座標で時間を無駄にするのは、お互いに望むことではありませんので。","ENG":"We don't want to waste time in the wrong place.","TWN":"我們誰都不想因為錯誤的座標而浪費時間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};